* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0a14; color: white; display: flex; justify-content: center; padding: 30px 20px; min-height: 100vh; }
.app { width: 100%; max-width: 380px; }
.tabs { display: flex; gap: 6px; background: rgba(255,255,255,0.04); border-radius: 14px; padding: 5px; margin-bottom: 28px; }
.tab { flex: 1; background: transparent; border: none; color: rgba(255,255,255,0.5); padding: 11px; border-radius: 10px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.tab.active { background: rgba(99,102,241,0.18); color: #818cf8; }
.panel { display: none; }
.panel.active { display: block; }
.clock-face { width: 240px; height: 240px; border-radius: 50%; border: 2px solid rgba(255,255,255,0.08); margin: 0 auto 24px; position: relative; }
.hand { position: absolute; bottom: 50%; left: 50%; transform-origin: bottom center; border-radius: 4px; }
.hand.hour { width: 6px; height: 60px; background: white; margin-left: -3px; }
.hand.minute { width: 4px; height: 85px; background: #818cf8; margin-left: -2px; }
.hand.second { width: 2px; height: 95px; background: #f87171; margin-left: -1px; }
.center-dot { position: absolute; top: 50%; left: 50%; width: 12px; height: 12px; background: white; border-radius: 50%; transform: translate(-50%, -50%); }
.digital-time { text-align: center; font-size: 32px; font-weight: 800; font-variant-numeric: tabular-nums; }
.date-label { text-align: center; color: rgba(255,255,255,0.4); font-size: 14px; margin-top: 6px; }
.alarm-list { display: flex; flex-direction: column; gap: 12px; margin-bottom: 20px; }
.alarm-item { display: flex; align-items: center; justify-content: space-between; background: rgba(255,255,255,0.04); border-radius: 14px; padding: 16px 18px; }
.alarm-time { font-size: 24px; font-weight: 800; }
.alarm-label { font-size: 12px; color: rgba(255,255,255,0.4); margin-top: 2px; }
.alarm-right { display: flex; align-items: center; gap: 12px; }
.toggle { width: 46px; height: 26px; background: rgba(255,255,255,0.1); border-radius: 999px; position: relative; cursor: pointer; transition: 0.2s; }
.toggle.on { background: #4ade80; }
.toggle-dot { position: absolute; top: 3px; left: 3px; width: 20px; height: 20px; background: white; border-radius: 50%; transition: 0.2s; }
.toggle.on .toggle-dot { left: 23px; }
.delete-btn { background: rgba(239,68,68,0.12); color: #f87171; border: none; width: 32px; height: 32px; border-radius: 8px; font-size: 14px; cursor: pointer; }
.add-alarm { display: flex; gap: 10px; }
.add-alarm input { flex: 1; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 12px; border-radius: 10px; font-size: 14px; }
.add-alarm button { background: linear-gradient(135deg, #6366f1, #818cf8); border: none; color: white; padding: 12px 18px; border-radius: 10px; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
.timer-display { text-align: center; font-size: 56px; font-weight: 800; font-variant-numeric: tabular-nums; margin: 30px 0; }
.timer-presets { display: flex; gap: 8px; justify-content: center; margin-bottom: 24px; flex-wrap: wrap; }
.timer-presets button { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 10px 16px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.timer-controls { display: flex; gap: 12px; justify-content: center; }
.timer-controls button { background: rgba(255,255,255,0.06); border: none; color: white; padding: 14px 30px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
.timer-controls button.primary { background: linear-gradient(135deg, #6366f1, #818cf8); }
.laps { margin-top: 24px; display: flex; flex-direction: column; gap: 8px; }
.lap-item { display: flex; justify-content: space-between; background: rgba(255,255,255,0.04); padding: 10px 16px; border-radius: 10px; font-size: 13px; font-weight: 600; color: rgba(255,255,255,0.6); }

