// Saat
function updateClock() {
  const now = new Date();
  const h = now.getHours() % 12;
  const m = now.getMinutes();
  const s = now.getSeconds();
  document.getElementById('hourHand').style.transform = `rotate(${h * 30 + m * 0.5}deg)`;
  document.getElementById('minuteHand').style.transform = `rotate(${m * 6}deg)`;
  document.getElementById('secondHand').style.transform = `rotate(${s * 6}deg)`;
  document.getElementById('digitalTime').textContent =
    `${String(now.getHours()).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  document.getElementById('dateLabel').textContent =
    now.toLocaleDateString('tr-TR', { weekday: 'long', day: 'numeric', month: 'long' });
}
setInterval(updateClock, 1000);
updateClock();

// Tabs
function switchTab(btn, id) {
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById(id).classList.add('active');
}

// Alarms
let alarms = [
  { time: '07:30', label: 'Uyanma', on: true },
  { time: '22:00', label: 'Uyku Vakti', on: false }
];

function renderAlarms() {
  const list = document.getElementById('alarmList');
  list.innerHTML = '';
  alarms.forEach((a, i) => {
    const div = document.createElement('div');
    div.className = 'alarm-item';
    div.innerHTML = `
      <div><div class="alarm-time">${a.time}</div><div class="alarm-label">${a.label}</div></div>
      <div class="alarm-right">
        <div class="toggle ${a.on ? 'on' : ''}" onclick="toggleAlarm(${i})"><div class="toggle-dot"></div></div>
        <button class="delete-btn" onclick="deleteAlarm(${i})">✕</button>
      </div>
    `;
    list.appendChild(div);
  });
}

function toggleAlarm(i) { alarms[i].on = !alarms[i].on; renderAlarms(); }
function deleteAlarm(i) { alarms.splice(i, 1); renderAlarms(); }
function addAlarm() {
  const time = document.getElementById('alarmTimeInput').value;
  if (!time) return;
  alarms.push({ time, label: 'Alarm', on: true });
  renderAlarms();
}
renderAlarms();

// Timer
let timerSeconds = 300;
let timerInterval = null;
let timerRunning = false;

function formatTimer(sec) {
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
}

function renderTimer() { document.getElementById('timerDisplay').textContent = formatTimer(timerSeconds); }

function setTimer(sec) {
  timerSeconds = sec;
  clearInterval(timerInterval);
  timerRunning = false;
  document.getElementById('timerBtn').textContent = 'Başlat';
  renderTimer();
}

function toggleTimer() {
  timerRunning = !timerRunning;
  document.getElementById('timerBtn').textContent = timerRunning ? 'Duraklat' : 'Başlat';
  if (timerRunning) {
    timerInterval = setInterval(() => {
      if (timerSeconds > 0) { timerSeconds--; renderTimer(); }
      else { clearInterval(timerInterval); timerRunning = false; document.getElementById('timerBtn').textContent = 'Başlat'; alert('Süre doldu!'); }
    }, 1000);
  } else {
    clearInterval(timerInterval);
  }
}

function resetTimer() { setTimer(300); }
renderTimer();

// Stopwatch
let swElapsed = 0;
let swInterval = null;
let swRunning = false;
let lapCount = 0;

function formatStopwatch(ms) {
  const m = Math.floor(ms / 60000);
  const s = Math.floor((ms % 60000) / 1000);
  const t = Math.floor((ms % 1000) / 100);
  return `${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}.${t}`;
}

function toggleStopwatch() {
  swRunning = !swRunning;
  document.getElementById('stopwatchBtn').textContent = swRunning ? 'Duraklat' : 'Başlat';
  if (swRunning) {
    const start = Date.now() - swElapsed;
    swInterval = setInterval(() => {
      swElapsed = Date.now() - start;
      document.getElementById('stopwatchDisplay').textContent = formatStopwatch(swElapsed);
    }, 100);
  } else {
    clearInterval(swInterval);
  }
}

function lapStopwatch() {
  if (!swRunning) return;
  lapCount++;
  const laps = document.getElementById('laps');
  const div = document.createElement('div');
  div.className = 'lap-item';
  div.innerHTML = `<span>Tur ${lapCount}</span><span>${formatStopwatch(swElapsed)}</span>`;
  laps.prepend(div);
}

function resetStopwatch() {
  clearInterval(swInterval);
  swElapsed = 0;
  swRunning = false;
  lapCount = 0;
  document.getElementById('stopwatchDisplay').textContent = '00:00.0';
  document.getElementById('stopwatchBtn').textContent = 'Başlat';
  document.getElementById('laps').innerHTML = '';
}
